import React, { useEffect, useState } from "react";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  ArcElement,
  Tooltip,
  Legend
} from "chart.js";

import { Bar, Pie } from "react-chartjs-2";

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  ArcElement,
  Tooltip,
  Legend
);

function Analytics() {
  const [stats, setStats] = useState({
    totalStudents: 0,
    placedStudents: 0,
    placementRate: 0,
    avgCGPA: 0
  });

  useEffect(() => {
    fetch("http://localhost:5000/api/analytics")
      .then(res => res.json())
      .then(data => setStats(data));
  }, []);

  const barData = {
    labels: ["Students"],
    datasets: [
      {
        label: "Placed Students",
        data: [stats.placedStudents],
        backgroundColor: "#3b82f6"
      }
    ]
  };

  const pieData = {
    labels: ["Placed", "Unplaced"],
    datasets: [
      {
        data: [
          stats.placedStudents,
          stats.totalStudents - stats.placedStudents
        ],
        backgroundColor: ["#22c55e", "#ef4444"]
      }
    ]
  };

  return (
    <div className="main">

      <h1>Placement Analytics</h1>

      <div className="cards">
        <div className="card">
          <h3>Total Students</h3>
          <p>{stats.totalStudents}</p>
        </div>

        <div className="card">
          <h3>Placed Students</h3>
          <p>{stats.placedStudents}</p>
        </div>

        <div className="card">
          <h3>Placement Rate</h3>
          <p>{stats.placementRate}%</p>
        </div>

        <div className="card">
          <h3>Average CGPA</h3>
          <p>{stats.avgCGPA}</p>
        </div>
      </div>

      <div style={{display:"flex", gap:"50px", marginTop:"50px"}}>

        <div style={{width:"500px"}}>
          <Bar data={barData}/>
        </div>

        <div style={{width:"350px"}}>
          <Pie data={pieData}/>
        </div>

      </div>

    </div>
  );
}

export default Analytics;
